SELECT t, Name, sum(ValueIncrease) AS ValueIncreaseAgg FROM (  SELECT t, Name, subName, if(runningDifference(Value) < 0 OR neighbor(subName,-1,subName) != subName, nan, runningDifference(Value) / 1) AS ValueIncrease  FROM (   SELECT (intDiv(toUInt32(event_time), 30) * 30) * 1000 AS t, Name, 'test2' AS subName, max(Value) AS Value   FROM default.test_grafana WHERE event_date >= toDate(1735787045) AND event_date <= toDate(1735790706) AND event_time >= toDateTime(1735787045) AND event_time <= toDateTime(1735790706)   GROUP BY Name, subName, t    ORDER BY Name, subName, t  ) ) GROUP BY Name, t ORDER BY Name, t